import sys
input = sys.stdin.read

def main():
    data = input().split()
    H = int(data[0])
    W = int(data[1])
    N = int(data[2])
    T = data[3]
    grid = data[4:4+H]

    current_positions = set()

    for i in range(H):
        for j in range(W):
            if grid[i][j] == '.':
                x, y = i, j
                valid = True
                for move in T:
                    if move == 'L':
                        y -= 1
                    elif move == 'R':
                        y += 1
                    elif move == 'U':
                        x -= 1
                    elif move == 'D':
                        x += 1
                    if x < 0 or x >= H or y < 0 or y >= W or grid[x][y] == '#':
                        valid = False
                        break
                if valid:
                    current_positions.add((x, y))

    print(len(current_positions))

if __name__ == "__main__":
    main()
